/// <summary>
/// Sussurro da Terra — ao recolher, regista "encontrado" na área
/// (<c>AreaProgress.whispersFound</c> / <c>AreaData.totalWhispers</c>) e
/// actualiza o contador global (<c>PlayerProgress.totalSussurrosCollected</c>,
/// via <c>AddWhisperFound</c>).
///
/// A "entrega" (<c>AreaProgress.whispersDelivered</c> — ex: a um NPC/altar
/// específico) é um passo distinto e NÃO é feita por este pickup; é registada
/// por uma Acção de diálogo/NPC chamando
/// <c>PlayerProgress.AddWhisperDelivered(area)</c> separadamente.
/// </summary>
public class SussurroDaTerraPickup : PickupBase
{
    public override PickupType Type => PickupType.SussurroDaTerra;

    protected override void GrantReward()
    {
        if (area != null) PlayerProgress.Instance?.AddWhisperFound(area);
    }
}
